import{_ as e}from"./plugin-vue_export-helper-c27b6911.js";import{r as s,o as i,c as l,a as n,b as o,e as t,f as c}from"./app-2b54a1a1.js";const r={},p=c(`<h3 id="css3" tabindex="-1"><a class="header-anchor" href="#css3" aria-hidden="true">#</a> CSS3</h3><p>CSS3 是 CSS（层叠样式表）的最新版本，相较于 CSS2，它引入了众多强大的新特性。主要集中在布局(Flexbox、Grid)、动画(transform、transition、animation)、响应式设计、视觉效果（阴影、渐变、动画）等方面</p><h3 id="_2d变换transform" tabindex="-1"><a class="header-anchor" href="#_2d变换transform" aria-hidden="true">#</a> 2D变换transform</h3><ol><li>2D位移: <code>transform: translate </code>位移与相对定位很相似，都不脱离文档流，不会影响到其它元素。浏览器针对位移有优化，与定位相比，浏览器处理位移的效率更高。</li><li>2D缩放:<code> transform: scale(0.5)</code>让元素放大或缩小,1表示不缩放,大于1放大小于1 缩小。scale不能作用与行内元素，得设置一下display。</li><li>2D旋转: <code>transform:rotate(20deg)</code>让元素在二维平面内，顺时针旋转或逆时针旋转。rotate设置旋转角度，需指定一个角度值( deg )，正值顺时针，负值逆时针。</li></ol><blockquote><ul><li>位移配合定位，可实现元素水平垂直居中<code>.box { position: absolute; left: 50%; top: 50%; transform: translate(-50%, -50%); } </code></li><li>借助缩放，可实现小于 12px 的文字。<code>transform: scale(0.5)</code></li><li><code>transform: translate(-50%, -50%) rotate(45deg); </code></li></ul></blockquote><h3 id="过渡transition" tabindex="-1"><a class="header-anchor" href="#过渡transition" aria-hidden="true">#</a> 过渡transition</h3><ol><li>transition:1s 1s linear all;</li><li>如果设置了一个时间，表示 duration( 设置过渡的持续时间) ；如果设置了两个时间，第一是 duration ，第二个是 delay ；其他值没有顺序要求。</li><li>linear过渡的类型，all ：过渡所有能过渡的属性。</li></ol><h3 id="动画animation" tabindex="-1"><a class="header-anchor" href="#动画animation" aria-hidden="true">#</a> 动画animation</h3><ol><li>一段动画，就是一段时间内连续播放 n 个画面。每一张画面管它叫做“帧”；关键帧指的是，在构成一段动画的若干帧中，起到决定性作用的 2-3 帧。</li><li>第一步：定义关键帧 <code>@keyframes keyName {from{...} to{...}}</code></li><li>第二步：给元素应用动画 <code>.inner {animation: keyName 3s 0.5s linear 2 alternate-reverse forwards; } </code><br> a. animation-name ：给元素指定具体的动画（具体的关键帧）;<br> b. animation-duration ：设置动画所需时间;<br> c. animation-delay ：设置动画延迟;</li></ol><h3 id="transition与animation区别是什么" tabindex="-1"><a class="header-anchor" href="#transition与animation区别是什么" aria-hidden="true">#</a> transition与animation区别是什么？</h3><ol><li>可以实现同样的效果，虽然写法不一样</li><li>区别①动画不需要触发条件，transition需要元素hover等等动作</li><li>区别②动画可以在过程中加关键帧，进行更加精细的控制</li></ol><div class="language-css line-numbers-mode" data-ext="css"><pre class="language-css"><code><span class="token comment">/*过渡实现inner1跑到右边去,需要元素hover动作*/</span>
<span class="token selector">.inner1</span><span class="token punctuation">{</span>
  <span class="token property">transition</span><span class="token punctuation">:</span>3s linear<span class="token punctuation">;</span>
<span class="token punctuation">}</span>
<span class="token selector">.outer:hover .inner1</span><span class="token punctuation">{</span>
  <span class="token property">transform</span><span class="token punctuation">:</span> <span class="token function">translate</span><span class="token punctuation">(</span>900px<span class="token punctuation">)</span>
<span class="token punctuation">}</span>

<span class="token comment">/*动画实现inner2跑到右边去,可以在过程中多加几个关键帧*/</span>
<span class="token atrule"><span class="token rule">@keyframes</span> go</span><span class="token punctuation">{</span>
  <span class="token selector">from</span><span class="token punctuation">{</span> <span class="token punctuation">}</span>
  <span class="token selector">to</span><span class="token punctuation">{</span> <span class="token property">transform</span><span class="token punctuation">:</span> <span class="token function">translate</span><span class="token punctuation">(</span>900px<span class="token punctuation">)</span><span class="token punctuation">;</span><span class="token punctuation">}</span>
<span class="token punctuation">}</span>
<span class="token selector">inner2</span><span class="token punctuation">{</span>
  <span class="token property">animation</span><span class="token punctuation">:</span> go 3s linear<span class="token punctuation">;</span>
<span class="token punctuation">}</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="伸缩盒模型flex" tabindex="-1"><a class="header-anchor" href="#伸缩盒模型flex" aria-hidden="true">#</a> 伸缩盒模型flex</h3><ol><li>Flexible Box （伸缩盒模型，又称：弹性盒子）。可以将元素的display属性值设置为flex从而成为一个flex容器，它里面所有的子元素都成为它的项目。它可以轻松的控制：元素分布方式、元素对齐方式、元素视觉顺序。</li><li>伸缩容器：开启了 flex 的元素就是伸缩容器；伸缩项目： 伸缩容器所有子元素自动成为了伸缩项目。</li><li>容器上属性</li></ol><blockquote><ul><li>flex-direction：指定主轴的方向 <code>flex-direation: row/row-reserve; </code>主轴方向从左到右/从右到左 <code>flex-direation: column/column-reserve; </code>主轴方向从上到下/从下到上</li><li>justify-content:指定项目在主轴的对齐方式；<code>justify-content: flex-start/flex-end/center/space-between(两端对齐)/space-evenly(两端距离与中间的一样)/space-around(两端距离是中间的一半)</code></li><li>align-items：指定项目在侧轴的对齐方式；<code>align-items: flex-start/flex-end/center/baseline/stretch(元素未设置高度则占满容器高度);</code></li><li>flex-wrap：项目是否换行； <code>flex-wrap: nowrap；</code>不换行；<code>flex-wrap: wrap；</code>自动换行</li><li>align-content：侧轴对齐方式多行；<code>align-content:flex-start/flex-end/center/space-between/space-evenly/space-around/stretch;</code></li></ul></blockquote><ol start="4"><li>项目上属性</li></ol><blockquote><ul><li>order：项目排列顺序,数值越小排列越前</li><li>flex-grow:当排列空间有剩余时候,项目的放大比例。默认为 0，即如果存在剩余空间，也不放大。</li><li>flex-shrink:当排列空间不足时候，指定项目的缩小比例。默认为 1，即如果空间不足，该项目将缩小。</li><li>flex-basis：是主轴方向的基准长度,默认值为 auto，即项目的本来大小,设置子元素宽度</li><li>align-self ：允许单个项目有与其他项目不一样的对齐方式</li></ul></blockquote><ol start="5"><li>flex是复合属性，包含了flex-grow flex-shrink flex-basis, 默认值是0 1 auto</li></ol><blockquote><ul><li>flex: 1; flex: 1 1 0;可以拉伸 可以压缩并设置基准长度为0</li><li>flex：auto;flex: 1 1 auto;可以拉伸 可以压缩 不设置基准长度</li><li>flex：none;flex: 0 0 auto;不可以拉伸 不可以压缩 不设置基准长度</li><li>flex: 0 auto;flex: 0 1 auto;默认值：不可以拉伸 可以压缩 不设置基准长度</li></ul></blockquote><ol start="6"><li>flex 实现水平垂直居中方式</li></ol><div class="language-css line-numbers-mode" data-ext="css"><pre class="language-css"><code><span class="token comment">/*第一种：父容器开启flex布局；再使用justify-content: center; align-items:center;实现居中 */</span>
<span class="token selector">.outer</span><span class="token punctuation">{</span>
  <span class="token property">width</span><span class="token punctuation">:</span> 400px<span class="token punctuation">;</span>
  <span class="token property">height</span><span class="token punctuation">:</span> 400px<span class="token punctuation">;</span>
  <span class="token property">background</span><span class="token punctuation">:</span> #ddd<span class="token punctuation">;</span>
  <span class="token property">display</span><span class="token punctuation">:</span> flex<span class="token punctuation">;</span>
  <span class="token property">justify-content</span><span class="token punctuation">:</span> center<span class="token punctuation">;</span>
  <span class="token property">align-items</span><span class="token punctuation">:</span> center<span class="token punctuation">;</span>
<span class="token punctuation">}</span>
<span class="token selector">.inner</span><span class="token punctuation">{</span>
  <span class="token property">width</span><span class="token punctuation">:</span> 100px<span class="token punctuation">;</span>
  <span class="token property">height</span><span class="token punctuation">:</span> 100px<span class="token punctuation">;</span>
  <span class="token property">background</span><span class="token punctuation">:</span> orange<span class="token punctuation">;</span>
<span class="token punctuation">}</span>
<span class="token comment">/*第二种：父容器开启flex布局；子元素margin:auto;  */</span>
<span class="token selector">.outer</span><span class="token punctuation">{</span>
  <span class="token property">width</span><span class="token punctuation">:</span> 400px<span class="token punctuation">;</span>
  <span class="token property">height</span><span class="token punctuation">:</span> 400px<span class="token punctuation">;</span>
  <span class="token property">background</span><span class="token punctuation">:</span> #ddd<span class="token punctuation">;</span>
  <span class="token property">display</span><span class="token punctuation">:</span> flex<span class="token punctuation">;</span>
<span class="token punctuation">}</span>
<span class="token selector">.inner</span><span class="token punctuation">{</span>
  <span class="token property">width</span><span class="token punctuation">:</span> 100px<span class="token punctuation">;</span>
  <span class="token property">height</span><span class="token punctuation">:</span> 100px<span class="token punctuation">;</span>
  <span class="token property">background</span><span class="token punctuation">:</span> orange<span class="token punctuation">;</span>
  <span class="token property">margin</span><span class="token punctuation">:</span> auto<span class="token punctuation">;</span>
<span class="token punctuation">}</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="bfc" tabindex="-1"><a class="header-anchor" href="#bfc" aria-hidden="true">#</a> BFC</h3><ol><li>是什么? BFC（Block Formatting Context）全称是块格式化上下文，是一个独立容器，容器内部的元素与外部的元素互不影响</li></ol><blockquote><ul><li>在 BFC 中上下相邻的两个容器的 margin 会重叠</li><li>计算 BFC 的高度时，需要计算浮动元素的高度</li><li>容器内部元素不会影响外部元素</li><li>BFC 区域不会与浮动的容器发生重叠</li></ul></blockquote><ol start="2"><li>怎么触发BFC? ①设置浮动<code> float:none以外的</code>；②设置绝对定位 <code>position：absolute、fixed；</code>③行内块元素或flex <code>display: inline-block flex</code>；④overflow值不为visiable的块元素<code> overflow:hidden scorll auto;</code>⑤表格单元格<code>table-cell、table-caption；</code></li><li>应用场景?</li></ol><blockquote><ul><li>垂直margin重叠问题:由于 BFC 是一个独立的区域,将两个元素变为两个 BFC，就解决了 margin 重叠的问题。</li><li>清除浮动，解决父元素高度塌陷问题：在对子元素设置浮动后，父元素会发生高度塌陷，父元素的高度变为 0，解决方式就是把父元素设为BFC <code>overflow: hidden</code></li><li>创建自适应两栏布局:可以用来创建自适应两栏布局：左边的宽度固定，右边的宽度自适应;左侧设置float:left，右侧设置overflow: hidden。这样右边就触发了 BFC，BFC 的区域不会与浮动元素发生重叠</li></ul></blockquote><h3 id="新增长度单位" tabindex="-1"><a class="header-anchor" href="#新增长度单位" aria-hidden="true">#</a> 新增长度单位</h3><ol><li>rem 根元素字体大小的倍数，只与根元素字体大小有关。</li><li>vw 视口宽度的百分之多少，10vw 就是视口宽度的 10% 。</li><li>vh 视口高度的百分之多少，10vh 就是视口高度的 10% 。</li></ol><blockquote><p>CSS2长度单位</p><ul><li>px ： 像素</li><li>em：相对于父元素的 <code>font-size</code>（例如，<code>1em = 父元素的字体大小</code>）</li><li>%：相对父元素计算</li><li>rpx: 微信小程序（WXSS）单位，无需手动计算，直接适配屏幕宽度。</li></ul></blockquote><h3 id="新增颜色设置方式" tabindex="-1"><a class="header-anchor" href="#新增颜色设置方式" aria-hidden="true">#</a> 新增颜色设置方式</h3><ol><li>新增了三种颜色设置方式，分别是： rgba 、 hsl 、 hsla</li><li>HSL 或 HSLA： 通过：色相、饱和度、亮度，来表示一个颜色的，格式为： hsl(色相,饱和度,亮度)</li></ol><blockquote><ul><li>色相：取值范围是 0~360 度 红是0度；绿色120度；蓝色240度</li><li>饱和度：取值范围是 0%~100% 。</li><li>亮度：取值范围是 0%~100% 。</li></ul></blockquote><h3 id="新增选择器" tabindex="-1"><a class="header-anchor" href="#新增选择器" aria-hidden="true">#</a> 新增选择器</h3><ol><li>新增的选择器有：动态伪类、目标伪类、语言伪类、 UI 伪类、结构伪类、否定伪类、伪元素</li><li>伪类选择器 : 像类( class )，但不是类，是元素的一种特殊状态。</li></ol><blockquote><ul><li>动态伪类：<code>:link :visited :hover :active :focus :checked</code></li><li>结构伪类：<code>:first-child :last-child :nth-child(n)第n个子元素 :first-of-type(n)所有同类型兄弟元素中的第一个</code></li></ul></blockquote><ol start="3"><li>伪元素选择器： 像元素，但是不是元素，是元素的一些特殊位置。</li></ol><blockquote><p>a. ::first-letter 选中元素中的第一个文字。<br> b. ::first-line 选中元素中的第一行文字。<br> c. ::selection 选中被鼠标选中的内容。<br> d. ::before 在元素最开始的位置，创建一个子元素（必须用 content 属性指定内容）。<br> e. ::after 在元素最后的位置，创建一个子元素（必须用 content 属性指定内容）。</p></blockquote><h3 id="新增盒模型相关属性" tabindex="-1"><a class="header-anchor" href="#新增盒模型相关属性" aria-hidden="true">#</a> 新增盒模型相关属性</h3><ol><li>盒模型都是由四个部分组成的，分别是<code> margin、border、padding 和 content</code>。盒子的大小 = content + 左右 padding + 左右 border；</li><li>类型:</li></ol><blockquote><ul><li>标准盒子模型：width/height 只是内容高度，不包含 padding 和 border值；</li><li>IE 盒模型：width/height 包含了 padding和 border值</li></ul></blockquote><ol start="3"><li>设置:</li></ol><blockquote><ul><li>box-sizing：content-box；width 和 height 设置的是盒子内容区的大小。（默认值）</li><li>box-sizing：border-box； width 和 height 设置的是盒子总大小。（IE盒模型）</li></ul></blockquote><h3 id="新增背景属性" tabindex="-1"><a class="header-anchor" href="#新增背景属性" aria-hidden="true">#</a> 新增背景属性</h3><ol><li>使用 box-shadow 属性为盒子添加阴影。<code>box-shadow: 10px 10px 10px red;</code></li><li>background-origin: 设置背景图的原点。</li><li>background-clip: 设置背景图的向外裁剪的区域。</li><li>background-size: 设置背景图的尺寸。<code>contain</code>:将背景图片等比缩放，使背景图片的宽或高与容器的宽或高相等;<code>cover</code>:将背景图片等比缩放，直到完全覆盖容器。</li></ol><h3 id="新增边框属性" tabindex="-1"><a class="header-anchor" href="#新增边框属性" aria-hidden="true">#</a> 新增边框属性</h3><p>border-radius 属性可以将盒子变为圆角。 <code>border-radius:10px;</code></p><h3 id="新增文本属性" tabindex="-1"><a class="header-anchor" href="#新增文本属性" aria-hidden="true">#</a> 新增文本属性</h3><ol><li>text-shadow 属性给文本添加阴影。</li><li>white-space 属性设置文本换行方式。 <code>normal</code> 文本超出边界自动换行，文本中的换行被浏览器识别为一个空格。（默认值） ;<code> nowrap</code> 强制不换行</li></ol><h3 id="新增渐变" tabindex="-1"><a class="header-anchor" href="#新增渐变" aria-hidden="true">#</a> 新增渐变</h3><ol><li>线性渐变 <code>background-image: linear-gradient(red,yellow,green);</code></li><li>径向渐变 <code>background-image: radial-gradient(red,yellow,green);</code></li></ol><h3 id="web-字体" tabindex="-1"><a class="header-anchor" href="#web-字体" aria-hidden="true">#</a> web 字体</h3><p>通过 @font-face 指定字体的具体地址，浏览器会自动下载该字体，这样就不依赖用户电脑上的字体了。 <code>@font-face { font-family: &quot;情书字体&quot;; src: url(&#39;./方正手迹.ttf&#39;); }</code></p><h3 id="link与-import引入css的区别" tabindex="-1"><a class="header-anchor" href="#link与-import引入css的区别" aria-hidden="true">#</a> link与@import引入CSS的区别</h3><ol><li>两者都是外部引用 CSS 的方式</li><li>用法上：<link rel="stylesheet" href="标签路径"> @import url(&quot;标签路径&quot;)</li><li>本质上：link 属于 XHTML 标签，而 @import 完全是 CSS 提供的一种方式。</li><li>加载顺序的差别：link 引用的 CSS 会同时被加载；而 @import 引用的 CSS 会等到页面全部被下载完再被加载</li><li>link 支持使用 Javascript 控制 DOM 去改变样式；而@import 不支持</li></ol><h3 id="隐藏元素的方法有哪些" tabindex="-1"><a class="header-anchor" href="#隐藏元素的方法有哪些" aria-hidden="true">#</a> 隐藏元素的方法有哪些</h3><ol><li>display:none 不渲染元素</li><li>visibility:hidden 渲染元素，但是不可见</li><li>opacity:0 透明度为0，元素不可见，占据页面空间，可以响应点击事件</li><li>transform:scale(0,0) 将元素缩放为0</li><li>position:absolute 将元素移出可视区域</li><li>z-index:负值，使其他元素遮盖住该元素</li></ol><blockquote><p>display:none与visibility:hidden的区别：</p><ul><li>display:none不会再页面占据位置，也不会响应绑定的点击事件，修改此属性会导致整个文档重排</li><li>visibility:hidden 元素在页面中仍占据空间，但是不会响应绑定的点击事件，修改此属性，只会导致当前元素重绘</li></ul></blockquote><h3 id="参考链接" tabindex="-1"><a class="header-anchor" href="#参考链接" aria-hidden="true">#</a> 参考链接</h3>`,58),d={href:"https://www.bilibili.com/video/BV1p84y1P7Z5/?spm_id_from=333.1387.search.video_card.click&vd_source=a3aec2a1dd5f478da3517872d0c61c5c",target:"_blank",rel:"noopener noreferrer"};function u(h,k){const a=s("ExternalLinkIcon");return i(),l("div",null,[p,n("p",null,[n("a",d,[o("html+css教程，前端html5+css3零基础入门，web前端开发"),t(a)])])])}const f=e(r,[["render",u],["__file","CSS3变化.html.vue"]]);export{f as default};
